function space_day_school_details_app_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('space_day_school_details_app');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'username' => parseCode('<%%creatorUsername%%>', true),
		'school_name' => Request::val('school_name', ''),
		'profile_type' => Request::val('profile_type', ''),
		'name_of_student_teacher' => Request::val('name_of_student_teacher', ''),
		'gender' => Request::val('gender', ''),
		'class_subject' => Request::val('class_subject', ''),
		'contact_number' => Request::val('contact_number', ''),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('space_day_school_details_app', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		space_day_school_details_app_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function space_day_school_details_app_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function space_day_school_details_app_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('space_day_school_details_app', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: space_day_school_details_app_before_delete
	if(function_exists('space_day_school_details_app_before_delete')) {
		$args = [];
		if(!space_day_school_details_app_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `space_day_school_details_app` WHERE `id`='{$selected_id}'", $eo);

	// hook: space_day_school_details_app_after_delete
	if(function_exists('space_day_school_details_app_after_delete')) {
		$args = [];
		space_day_school_details_app_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='space_day_school_details_app' AND `pkValue`='{$selected_id}'", $eo);
}

function space_day_school_details_app_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('space_day_school_details_app', $selected_id, 'edit')) return false;

	$data = [
		'school_name' => Request::val('school_name', ''),
		'profile_type' => Request::val('profile_type', ''),
		'name_of_student_teacher' => Request::val('name_of_student_teacher', ''),
		'gender' => Request::val('gender', ''),
		'class_subject' => Request::val('class_subject', ''),
		'contact_number' => Request::val('contact_number', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('space_day_school_details_app', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: space_day_school_details_app_before_update
	if(function_exists('space_day_school_details_app_before_update')) {
		$args = ['old_data' => $old_data];
		if(!space_day_school_details_app_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'space_day_school_details_app',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="space_day_school_details_app_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('space_day_school_details_app', $data['selectedID'], calculated_fields()['space_day_school_details_app']);

	// hook: space_day_school_details_app_after_update
	if(function_exists('space_day_school_details_app_after_update')) {
		if($row = getRecord('space_day_school_details_app', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!space_day_school_details_app_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('space_day_school_details_app', $selected_id);
}

