	// ajaxed auto-fill fields
	$templateCode .= '<script>';
	$templateCode .= '$j(function() {';


	$templateCode.="});";
	$templateCode.="</script>";
	$templateCode .= $lookups;

	// handle enforced parent values for read-only lookup fields
	$filterField = Request::val('FilterField');
	$filterOperator = Request::val('FilterOperator');
	$filterValue = Request::val('FilterValue');

	// don't include blank images in lightbox gallery
	$templateCode = preg_replace('/blank.gif" data-lightbox=".*?"/', 'blank.gif"', $templateCode);

	// don't display empty email links
	$templateCode=preg_replace('/<a .*?href="mailto:".*?<\/a>/', '', $templateCode);

	/* default field values */
	$rdata = $jdata = get_defaults('space_day_school_details_app');
	if($hasSelectedId) {
		$jdata = get_joined_record('space_day_school_details_app', $selectedId);
		if($jdata === false) $jdata = get_defaults('space_day_school_details_app');
		$rdata = $row;
	}
	$templateCode .= loadView('space_day_school_details_app-ajax-cache', ['rdata' => $rdata, 'jdata' => $jdata]);

	// hook: space_day_school_details_app_dv
	if(function_exists('space_day_school_details_app_dv')) {
		$args = [];
		space_day_school_details_app_dv(($hasSelectedId ? $selectedId : FALSE), getMemberInfo(), $templateCode, $args);
	}

	return $templateCode;
